arguments.new_str:
namespace Warehouse;

public sealed class InventoryTracker
{
    private readonly Dictionary<string, Dictionary<string, int>> _stock = new();
    private readonly int _reorderThreshold;

    public InventoryTracker(int reorderThreshold = 10)
    {
        if (reorderThreshold < 0)
            throw new ArgumentOutOfRangeException(nameof(reorderThreshold));
        _reorderThreshold = reorderThreshold;
    }

    public int GetStockLevel(string sku)
    {
        ArgumentException.ThrowIfNullOrEmpty(sku);
        int total = 0;
        foreach (var warehouse in _stock.Values)
        {
            if (warehouse.TryGetValue(sku, out int qty))
                total += qty;
        }
        return total;
    }

    public int GetStockLevel(string sku, string warehouse)
    {
        ArgumentException.ThrowIfNullOrEmpty(sku);
        ArgumentException.ThrowIfNullOrEmpty(warehouse);
        if (_stock.TryGetValue(warehouse, out var items) && items.TryGetValue(sku, out int qty))
            return qty;
        return 0;
    }

    public void AddStock(string sku, int quantity, string warehouse = "default")
    {
        ArgumentException.ThrowIfNullOrEmpty(sku);
        ArgumentException.ThrowIfNullOrEmpty(warehouse);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");

        if (!_stock.TryGetValue(warehouse, out var items))
        {
            items = new Dictionary<string, int>();
            _stock[warehouse] = items;
        }

        items.TryGetValue(sku, out int current);
        items[sku] = current + quantity;
    }

    public bool NeedsReorder(string sku)
    {
        return GetStockLevel(sku) < _reorderThreshold;
    }

    public void TransferStock(string sku, int quantity, string fromWarehouse, string toWarehouse)
    {
        ArgumentException.ThrowIfNullOrEmpty(sku);
        ArgumentException.ThrowIfNullOrEmpty(fromWarehouse);
        ArgumentException.ThrowIfNullOrEmpty(toWarehouse);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");
        if (fromWarehouse == toWarehouse)
            throw new ArgumentException("Source and destination warehouses must differ.");

        if (!_stock.TryGetValue(fromWarehouse, out var sourceItems)
            || !sourceItems.TryGetValue(sku, out int sourceQty)
            || sourceQty < quantity)
        {
            throw new InvalidOperationException(
                $"Insufficient stock for '{sku}' in warehouse '{fromWarehouse}'.");
        }

        sourceItems[sku] = sourceQty - quantity;

        if (!_stock.TryGetValue(toWarehouse, out var destItems))
        {
            destItems = new Dictionary<string, int>();
            _stock[toWarehouse] = destItems;
        }

        destItems.TryGetValue(sku, out int destQty);
        destItems[sku] = destQty + quantity;
    }
}

