using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Warehouse.Tests;

[TestClass]
public class StockLevelTests
{
    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        var tracker = new InventoryTracker();
        Assert.AreEqual(0, tracker.GetStockLevel("UNKNOWN-SKU"));
    }

    [TestMethod]
    public void AddStock_ThenGetStockLevel_ReturnsQuantity()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-001", 25);
        Assert.AreEqual(25, tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void AddStock_MultipleTimes_Accumulates()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-001", 10);
        tracker.AddStock("SKU-001", 15);
        Assert.AreEqual(25, tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void AddStock_DifferentSkus_TrackedIndependently()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-A", 5);
        tracker.AddStock("SKU-B", 20);

        Assert.AreEqual(5, tracker.GetStockLevel("SKU-A"));
        Assert.AreEqual(20, tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void GetStockLevel_AggregatesAcrossWarehouses()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-001", 10, "warehouse-east");
        tracker.AddStock("SKU-001", 30, "warehouse-west");

        Assert.AreEqual(40, tracker.GetStockLevel("SKU-001"));
    }

    [TestMethod]
    public void GetStockLevel_ByWarehouse_ReturnsWarehouseQuantityOnly()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-001", 10, "warehouse-east");
        tracker.AddStock("SKU-001", 30, "warehouse-west");

        Assert.AreEqual(10, tracker.GetStockLevel("SKU-001", "warehouse-east"));
        Assert.AreEqual(30, tracker.GetStockLevel("SKU-001", "warehouse-west"));
    }

    [TestMethod]
    public void GetStockLevel_ByWarehouse_UnknownWarehouse_ReturnsZero()
    {
        var tracker = new InventoryTracker();
        tracker.AddStock("SKU-001", 10, "warehouse-east");

        Assert.AreEqual(0, tracker.GetStockLevel("SKU-001", "warehouse-north"));
    }
}

