[TestClass]
public class ReorderAlertTests
{
    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        var tracker = new InventoryTracker(reorderThreshold: 20);
        tracker.AddStock("SKU-001", 10);

        Assert.IsTrue(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtThreshold_ReturnsFalse()
    {
        var tracker = new InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-001", 10);

        Assert.IsFalse(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        var tracker = new InventoryTracker(reorderThreshold: 10);
        tracker.AddStock("SKU-001", 50);

        Assert.IsFalse(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_UnknownSku_ReturnsTrue()
    {
        var tracker = new InventoryTracker(reorderThreshold: 5);
        Assert.IsTrue(tracker.NeedsReorder("NONEXISTENT"));
    }

    [TestMethod]
    public void NeedsReorder_ZeroThreshold_ZeroStock_ReturnsFalse()
    {
        var tracker = new InventoryTracker(reorderThreshold: 0);
        Assert.IsFalse(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    public void NeedsReorder_UsesAggregateAcrossWarehouses()
    {
        var tracker = new InventoryTracker(reorderThreshold: 20);
        tracker.AddStock("SKU-001", 8, "east");
        tracker.AddStock("SKU-001", 8, "west");

        // 16 total — still below 20
        Assert.IsTrue(tracker.NeedsReorder("SKU-001"));

        tracker.AddStock("SKU-001", 5, "east");
        // 21 total — above 20
        Assert.IsFalse(tracker.NeedsReorder("SKU-001"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void Constructor_NegativeThreshold_Throws()
    {
        new InventoryTracker(reorderThreshold: -1);
    }
}

